parameters.text:
={{
  (() => {
    const blocks = $json.blocks || [];

    let hasUser = false;
    let textBlock = null;

    for (const block of blocks) {
      for (const el of block.elements || []) {
        for (const inner of el.elements || []) {
          if (inner.type === 'user') {
            hasUser = true;
          }

          if (inner.type === 'text' && inner.text?.trim()) {
            textBlock = inner.text.trim();
          }
        }
      }
    }

    const hasText = !!textBlock;
    const hasThreadTs = !!$json.thread_ts;

    if (
      (hasUser && hasText) ||
      (hasText && hasThreadTs && !hasUser)
    ) {
      return textBlock;
    }

    return null;
  })()
}}

